[Form]
public class KPMGCommon_CertificateAnalysisLogo extends FormRun
{
    container imageContainer;
    str imageFilePathName;

    InventParameters inventParameters;

}

private void delete()
{
    ttsbegin;
    inventParameters = InventParameters::find(true);
    if (inventParameters)
    {
        inventParameters.KPMGCommon_CertificateAnalysisLogo = conNull();
        inventParameters.doUpdate();
    }
    ttscommit;

    imageContainer = conNull();
    imageFilePathName = '';
    element.showLogo();
}

public void init()
{
    super();

    Common callerRecord = element.args().record();

    if (callerRecord == null)
    {
        throw error(strFmt("@SYS22640", funcName()));
    }

    // Resolve with deliverable 552760
    // <GSA>
    //if (LedgerParameters::find().IsZakatEnabled_SA && refTableId == tableNum(LedgerReportIndexZakat_SA))
    //{
    //    LedgerReportIndexZakat_SA ledgerReportIndexZakat;

    //    select firstonly RecId
    //        from ledgerReportIndexZakat;

    //    refRecId = ledgerReportIndexZakat.RecId;
    //}
    // </GSA>

    inventParameters = InventParameters::find();
    if (inventParameters)
    {
        imageContainer = inventParameters.KPMGCommon_CertificateAnalysisLogo;
    }

    AccessRight menuItemAccessRight = FormSecurity::getMenuItemAccessRight(this);
    this.makeButtonsVisible(menuItemAccessRight);
}

void insert()
{
    ttsbegin;
    inventParameters = InventParameters::find(true);
    if (inventParameters)
    {
        inventParameters.KPMGCommon_CertificateAnalysisLogo = imageContainer;
        inventParameters.doUpdate();
    }
    ttscommit;
}

private void makeButtonsVisible(AccessRight _menuItemAccessRight)
{

    switch (_menuItemAccessRight)
    {
        case AccessRight::View:
            change.visible(false);
            remove.visible(false);
            break;
        case AccessRight::Add:
        case AccessRight::Edit:
            remove.visible(false);
            break;
    }
}

private void showLogo()
{
    Image logoImage;

    try
    {
        if (imageContainer)
        {
            logoImage = new Image();
            logoImage.setData(imageContainer);
            image.image(logoImage);
        }
        else
        {
            image.image(null);
        }
    }
    catch (Exception::Warning)
    {
        throw error(strFmt("@SYS19312", imageFilePathName));
    }
}

public void clicked()
{
    FileUploadTemporaryStorageResult fileUploadResult = File::GetFileFromUser(classstr(ImageFileUploadTemporaryStorageStrategy));

    if (fileUploadResult != null && fileUploadResult.getUploadStatus())
    {
        imageFilePathName = fileUploadResult.getDownloadUrl();
        imageContainer = ImageReference::GetPackedBinaryData(imageFilePathName);

        element.showLogo();
        element.insert();
    }
}
